type ToastInput = {
  title?: string;
  description?: string;
  variant?: "default" | "destructive";
};

export function toast(input: ToastInput) {
  if (typeof window === "undefined") return;
  const message = [input.title, input.description].filter(Boolean).join("\n");
  window.setTimeout(() => window.alert(message || "Done"), 0);
}

export function useToast() {
  return { toast };
}
